sql:
SELECT formation_name
FROM formations
WHERE formation_name LIKE '%carbonate%';

SELECT formation_name, formation_description
FROM formations
WHERE formation_id = 0;

external_knowledge:
- 'primary site' refers to 'Location 1';
- 'certain type of test' refers to 'test1';
- 'current, active well operations' refers to wells with 'active' status;
- 'relevant measurements' include measured depth, tensile strength, bulk density, measurement date, and notes;
- 'formation specifics' include formation name, depth, thickness, and description;
- 'tests performed' include test type name, description, equipment, and duration;
- 'orientation data' includes orientation name, description, and angle;
- 'group information' includes group name, description, and properties.

